    auto *stride_h = attrs->GetAttrPointer<int>(0);
    auto *stride_w = attrs->GetAttrPointer<int>(1);
    auto *padding_h = attrs->GetAttrPointer<int>(2);
    auto *padding_w = attrs->GetAttrPointer<int>(3);
